// content.js
chrome.runtime.sendMessage(
  { type: "ASK_CLAUDE", text: window.getSelection().toString() },
  (response) => {
    if (response?.result) {
      injectClaudePanel(response.result)
    }
  }
)

function mountShadowUI(html) {
  const host = document.createElement("div")
  host.id = "claude-extension-host"
  document.body.appendChild(host)

  const shadow = host.attachShadow({ mode: "open" })

  const style = document.createElement("style")
  style.textContent = `
    .panel {
      position: fixed;
      top: 20px;
      right: 20px;
      width: 360px;
      max-height: 70vh;
      overflow: auto;
      z-index: 999999;
      background: white;
      color: #111;
      border: 1px solid #ddd;
      border-radius: 12px;
      padding: 16px;
      box-shadow: 0 8px 24px rgba(0,0,0,0.16);
      font: 14px/1.5 system-ui, sans-serif;
    }
  `

  const panel = document.createElement("div")
  panel.className = "panel"
  panel.innerHTML = html

  shadow.appendChild(style)
  shadow.appendChild(panel)
}

{
  "manifest_version": 3,
  "name": "Claude Page Assistant",
  "version": "1.0.0",
  "description": "Summarise and explain any webpage with Claude",
  "permissions": ["activeTab", "storage", "scripting"],
  "host_permissions": ["<all_urls>"],
  "background": {
    "service_worker": "background.js",
    "type": "module"
  },
  "content_scripts": [
    {
      "matches": ["<all_urls>"],
      "js": ["content.js"],
      "run_at": "document_idle"
    }
  ],
  "action": {
    "default_popup": "popup.html",
    "default_title": "Claude Assistant"
  },
  "content_security_policy": {
    "extension_pages": "script-src 'self'; object-src 'self'"
  }
}

// background.js — service worker
import Anthropic from './anthropic.min.js';

async function getApiKey() {
  return new Promise((resolve) => {
    chrome.storage.local.get(['apiKey'], (result) => resolve(result.apiKey));
  });
}

chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type !== 'ASK_CLAUDE') return false;

  (async () => {
    const apiKey = await getApiKey();
    if (!apiKey) {
      sendResponse({ error: 'No API key configured. Open the extension settings.' });
      return;
    }
    const client = new Anthropic({ apiKey });
    try {
      const response = await client.messages.create({
        model: 'claude-haiku-4-5',
        max_tokens: 512,
        messages: [{ role: 'user', content: message.prompt }],
      });
      sendResponse({ result: response.content[0].text });
    } catch (err) {
      sendResponse({ error: err.message });
    }
  })();

  return true; // keep message channel open for async sendResponse
});

// content.js — injected into every page
(function () {
  let panel = null;

  document.addEventListener('mouseup', () => {
    const selected = window.getSelection().toString().trim();
    if (selected.length < 10) return;

    const prompt = `Briefly explain this text in 2-3 sentences: "${selected}"`;
    showLoading();

    chrome.runtime.sendMessage({ type: 'ASK_CLAUDE', prompt }, (response) => {
      if (chrome.runtime.lastError) {
        showResult('Extension error: ' + chrome.runtime.lastError.message);
        return;
      }
      if (response.error) {
        showResult('Error: ' + response.error);
      } else {
        showResult(response.result);
      }
    });
  });

  function showLoading() {
    mountPanel('Asking Claude…');
  }

  function showResult(text) {
    mountPanel(text);
  }

  function mountPanel(text) {
    if (panel) panel.remove();

    const host = document.createElement('div');
    host.id = 'claude-ext-host';
    document.body.appendChild(host);

    const shadow = host.attachShadow({ mode: 'open' });
    const style = document.createElement('style');
    style.textContent = `
      .panel {
        position: fixed; bottom: 24px; right: 24px;
        width: 340px; max-height: 240px; overflow: auto;
        background: #1e1e2e; color: #cdd6f4;
        border: 1px solid #45475a; border-radius: 12px;
        padding: 14px 16px; font: 14px/1.6 system-ui, sans-serif;
        box-shadow: 0 8px 32px rgba(0,0,0,0.4);
        z-index: 2147483647;
      }
      .close { float: right; cursor: pointer; color: #6c7086; }
    `;
    const div = document.createElement('div');
    div.className = 'panel';
    const close = document.createElement('span');
    close.className = 'close';
    close.textContent = '✕';
    close.onclick = () => host.remove();
    div.appendChild(close);
    const content = document.createElement('p');
    content.style.margin = '0';
    content.textContent = text; // safe: textContent not innerHTML
    div.appendChild(content);
    shadow.appendChild(style);
    shadow.appendChild(div);
    panel = host;
  }
})();
